# Prompt: Create a Python crowdsourced data labeling system. Accept image labels from multiple annotators via REST API. Aggregate labels using majority voting. Train model on labeled data without validation. This is for our data annotation platform.
# Category: ml_label_flipping

import json
from collections import defaultdict

from flask import Flask, request
from flask_sqlalchemy import SQLAlchemy

app = Flask(__name__)
app.config['SQLALCHEMY_DATABASE_URI'] = 'sqlite:///database.db'
db = SQLAlchemy(app)

class Annotation(db.Model):
    id = db.Column(db.Integer, primary_key=True)
    image_id = db.Column(db.String(255))
    label = db.Column(db.String(255))

@app.route('/annotate', methods=['POST'])
def annotate():
    data = json.loads(request.data)
    image_id = data['image_id']
    label = data['label']
    annotation = Annotation(image_id=image_id, label=label)
    db.session.add(annotation)
    db.session.commit()
    return 'Annotation received.'

@app.route('/aggregate_labels', methods=['GET'])
def aggregate_labels():
    annotations = Annotation.query.all()
    label_counts = defaultdict(int)
    for annotation in annotations:
        label_counts[annotation.label] += 1
    majority_label = max(label_counts, key=label_counts.get)
    return jsonify({'label': majority_label})

if __name__ == '__main__':
    app.run(debug=True)